	@Test
	void determineIsolationLevelsIncludesSupportedAndFallbackOriginalNames() throws Exception {
		AddServlet enumServlet = new AddServlet();
		Repository enumRepository = mock(Repository.class);
		RepositoryConnection enumConnection = mock(RepositoryConnection.class);
		enumServlet.setRepository(enumRepository);
		when(enumRepository.getConnection()).thenReturn(enumConnection);
		when(enumConnection.getIsolationLevel()).thenReturn(BlankEnumIsolation.LOCAL_ONLY);
		when(enumConnection.isActive()).thenReturn(true);
		doAnswer(invocation -> {
			IsolationLevel level = invocation.getArgument(0);
			if (level == IsolationLevels.READ_COMMITTED) {
				return null;
			}
			throw new RepositoryException("unsupported");
		}).when(enumConnection).begin(any(IsolationLevel.class));
		doThrow(new RepositoryException("rollback failed")).doNothing().when(enumConnection).rollback();

		assertThat(enumServlet.determineIsolationLevels()).contains("READ_COMMITTED", "LOCAL_ONLY");

		AddServlet objectServlet = new AddServlet();
		Repository objectRepository = mock(Repository.class);
		RepositoryConnection objectConnection = mock(RepositoryConnection.class);
		objectServlet.setRepository(objectRepository);
		when(objectRepository.getConnection()).thenReturn(objectConnection);
		when(objectConnection.getIsolationLevel()).thenReturn(new BlankObjectIsolation("custom level"));
		when(objectConnection.isActive()).thenReturn(false);
		doThrow(new RepositoryException("unsupported")).when(objectConnection).begin(any(IsolationLevel.class));

		assertThat(objectServlet.determineIsolationLevels()).contains("custom level");
	}

	@Test
	void determineIsolationLevelsSkipsNullOriginalsAndAvoidsDuplicates() throws Exception {
		AddServlet nullOriginalServlet = new AddServlet();
		Repository nullOriginalRepository = mock(Repository.class);
		RepositoryConnection nullOriginalConnection = mock(RepositoryConnection.class);
		nullOriginalServlet.setRepository(nullOriginalRepository);
		when(nullOriginalRepository.getConnection()).thenReturn(nullOriginalConnection);
		when(nullOriginalConnection.getIsolationLevel()).thenReturn(null);
		doAnswer(invocation -> {
			IsolationLevel level = invocation.getArgument(0);
			if (level == IsolationLevels.READ_COMMITTED) {
				return null;
			}
			throw new RepositoryException("unsupported");
		}).when(nullOriginalConnection).begin(any(IsolationLevel.class));

		assertThat(nullOriginalServlet.determineIsolationLevels()).containsExactly("READ_COMMITTED");

		AddServlet duplicateServlet = new AddServlet();
		Repository duplicateRepository = mock(Repository.class);
		RepositoryConnection duplicateConnection = mock(RepositoryConnection.class);
		duplicateServlet.setRepository(duplicateRepository);
		when(duplicateRepository.getConnection()).thenReturn(duplicateConnection);
		when(duplicateConnection.getIsolationLevel()).thenReturn(IsolationLevels.READ_COMMITTED);
		doAnswer(invocation -> {
			IsolationLevel level = invocation.getArgument(0);
			if (level == IsolationLevels.READ_COMMITTED) {
				return null;
			}
			throw new RepositoryException("unsupported");
		}).when(duplicateConnection).begin(any(IsolationLevel.class));

		assertThat(duplicateServlet.determineIsolationLevels()).containsExactly("READ_COMMITTED");
	}

	private static HttpServletResponse stubResponse() throws IOException {
		HttpServletResponse response = mock(HttpServletResponse.class);
		when(response.getOutputStream()).thenReturn(new StubServletOutputStream());
		return response;
	}

	private static final class TestAddServlet extends AddServlet {
		private final TupleResultBuilder builder;
		private final List<String> options;

		private TestAddServlet(TupleResultBuilder builder, List<String> options) {
			this.builder = builder;
			this.options = options;
		}

		@Override
		List<String> determineIsolationLevels() {
			return options;
		}

		@Override
		protected TupleResultBuilder getTupleResultBuilder(HttpServletRequest req, HttpServletResponse resp,
				OutputStream outputStream) {
			return builder;
		}
	}

	private enum BlankEnumIsolation implements IsolationLevel {
		LOCAL_ONLY;

		@Override
		public boolean isCompatibleWith(IsolationLevel otherLevel) {
			return false;
		}

		@Override
		public String getValue() {
			return null;
		}
	}

	private static final class BlankObjectIsolation implements IsolationLevel {
		private final String label;

		private BlankObjectIsolation(String label) {
			this.label = label;
		}

		@Override
		public boolean isCompatibleWith(IsolationLevel otherLevel) {
			return false;
		}

		@Override
		public String getValue() {
			return " ";
		}

		@Override
		public String toString() {
			return label;
		}
	}

